com.mirth.connect.plugins.javascriptrule.script:
// Parse the incoming JSON snapshot from plc_exporter
var snapshot = JSON.parse(msg);

channelMap.put('snapshot_timestamp', snapshot.timestamp || new Date().toISOString());

var vitals = snapshot.devices && snapshot.devices.plc_signosvitales
  ? snapshot.devices.plc_signosvitales.readings || {}
  : {};

var perfusor = snapshot.devices && snapshot.devices.plc_perfusor
  ? snapshot.devices.plc_perfusor.readings || {}
  : {};

var cpap = snapshot.devices && snapshot.devices.plc_cpap
  ? snapshot.devices.plc_cpap.readings || {}
  : {};

var hospital = snapshot.devices && snapshot.devices.plc_hospital
  ? snapshot.devices.plc_hospital.readings || {}
  : {};

channelMap.put('vitals', vitals);
channelMap.put('perfusor', perfusor);
channelMap.put('cpap', cpap);
channelMap.put('hospital', hospital);

logger.info('PLC snapshot processed: ' + snapshot.timestamp);

// ----------------------------------------------------------------
// Build HL7 v2.5.1 ORU^R01 message from PLC vital-signs snapshot
// ----------------------------------------------------------------
var vitals   = channelMap.get('vitals')   || {};
var hospital = channelMap.get('hospital') || {};
var ts       = channelMap.get('snapshot_timestamp') || new Date().toISOString();

// HL7 timestamp format: YYYYMMDDHHmmss
var hl7ts = ts.replace(/[-:T]/g,'').substring(0, 14);
var msgId = 'PLC' + hl7ts;

function val(obj, key, fallback) {
  var v = obj[key];
  return (v !== null && v !== undefined) ? v : fallback;
}

// Temperature stored as integer in PLC (e.g. 36 → 36.0)
var temp     = val(vitals, 'signosvitales_temp', '');
var frecuencia = val(vitals, 'signosvitales_frecuencia', '');
var presBaja   = val(vitals, 'signosvitales_presion_baja', '');
var presAlta   = val(vitals, 'signosvitales_presion_alta', '');
var spo2       = val(vitals, 'signosvitales_saturacion', '');
var respRate   = val(vitals, 'signosvitales_rate', '');

var lines = [
  // MSH
  'MSH|^~\\&|PLC_EXPORTER|HOSPITAL_GIZMO|MIRTH_CONNECT|OPENEMR|' + hl7ts + '||ORU^R01^ORU_R01|' + msgId + '|P|2.5.1|||AL|AL|',
  // PID — generic patient; update with real patient mapping when integrating OpenEMR
  'PID|1||GIZMO_PATIENT_001^^^HOSPITAL_GIZMO&HOSPITAL&L||Paciente^Virtual||19800101|U|',
  // OBR — vital signs panel
  'OBR|1|||85353-1^Vital signs panel^LN|||' + hl7ts + '|||||||||||||||F',
  // OBX 1 — Heart Rate
  'OBX|1|NM|8867-4^Heart rate^LN||' + frecuencia + '|/min|60-100||||F|||' + hl7ts,
  // OBX 2 — Systolic BP
  'OBX|2|NM|8480-6^Systolic blood pressure^LN||' + presAlta + '|mm[Hg]|100-140||||F|||' + hl7ts,
  // OBX 3 — Diastolic BP
  'OBX|3|NM|8462-4^Diastolic blood pressure^LN||' + presBaja + '|mm[Hg]|60-90||||F|||' + hl7ts,
  // OBX 4 — SpO2
  'OBX|4|NM|59408-5^Oxygen saturation^LN||' + spo2 + '|%|95-100||||F|||' + hl7ts,
  // OBX 5 — Respiratory Rate
  'OBX|5|NM|9279-1^Respiratory rate^LN||' + respRate + '|/min|12-20||||F|||' + hl7ts,
  // OBX 6 — Body Temperature
  'OBX|6|NM|8310-5^Body temperature^LN||' + temp + '|Cel|36.1-37.2||||F|||' + hl7ts,
  // OBX 7 — O2 Tank level (hospital infrastructure)
  'OBX|7|NM|HOSP-O2-TANK^Hospital O2 Tank^LOCAL||' + val(hospital, 'hospital_oxigeno_tanque', '') + '|%|||||F|||' + hl7ts,
];

tmp = lines.join('\r');

// Build a FHIR R4 Observation bundle for vital signs
// Called when Destination 2 is enabled (OpenEMR FHIR integration)
var vitals = channelMap.get('vitals') || {};
var ts     = channelMap.get('snapshot_timestamp') || new Date().toISOString();

function obs(id, loincCode, loincDisplay, value, unit, system) {
  return {
    resource: {
      resourceType: 'Observation',
      status: 'final',
      code: {
        coding: [{system: 'http://loinc.org', code: loincCode, display: loincDisplay}]
      },
      subject: {reference: 'Patient/gizmo-patient-001'},
      effectiveDateTime: ts,
      valueQuantity: {value: value, unit: unit, system: 'http://unitsofmeasure.org', code: system}
    },
    request: {method: 'POST', url: 'Observation'}
  };
}

var entries = [];

if (vitals.signosvitales_frecuencia !== null && vitals.signosvitales_frecuencia !== undefined)
  entries.push(obs(1, '8867-4', 'Heart rate', vitals.signosvitales_frecuencia, '/min', '/min'));
if (vitals.signosvitales_presion_alta !== null && vitals.signosvitales_presion_alta !== undefined)
  entries.push(obs(2, '8480-6', 'Systolic blood pressure', vitals.signosvitales_presion_alta, 'mmHg', 'mm[Hg]'));
if (vitals.signosvitales_presion_baja !== null && vitals.signosvitales_presion_baja !== undefined)
  entries.push(obs(3, '8462-4', 'Diastolic blood pressure', vitals.signosvitales_presion_baja, 'mmHg', 'mm[Hg]'));
if (vitals.signosvitales_saturacion !== null && vitals.signosvitales_saturacion !== undefined)
  entries.push(obs(4, '59408-5', 'Oxygen saturation', vitals.signosvitales_saturacion, '%', '%'));
if (vitals.signosvitales_rate !== null && vitals.signosvitales_rate !== undefined)
  entries.push(obs(5, '9279-1', 'Respiratory rate', vitals.signosvitales_rate, '/min', '/min'));
if (vitals.signosvitales_temp !== null && vitals.signosvitales_temp !== undefined)
  entries.push(obs(6, '8310-5', 'Body temperature', vitals.signosvitales_temp, 'Cel', 'Cel'));

var bundle = {
  resourceType: 'Bundle',
  type: 'transaction',
  entry: entries
};

tmp = JSON.stringify(bundle, null, 2);
